1526:
WITH customer_id AS (
    SELECT CustomerID FROM transactions_1k WHERE Date = '2012-08-25' AND Amount = 634.8
),
consumption_2012 AS (
    SELECT SUM(Consumption) AS consumption_2012 FROM yearmonth WHERE CustomerID IN (SELECT CustomerID FROM customer_id) AND SUBSTR(Date, 1, 4) = '2012'
),
consumption_2013 AS (
    SELECT SUM(Consumption) AS consumption_2013 FROM yearmonth WHERE CustomerID IN (SELECT CustomerID FROM customer_id) AND SUBSTR(Date, 1, 4) = '2013'
)
SELECT 
    (consumption_2012.consumption_2012 - consumption_2013.consumption_2013) / consumption_2012.consumption_2012 AS consumption_decrease_rate
FROM 
    consumption_2012, consumption_2013;

